const raw = $input.first().json;
const body = raw.body || raw;
const lead = {
  nome: body.nome || body.title || body.address || 'Lead Apify ' + new Date().toISOString().substring(0,10),
  cidade: body.cidade || body.city || body.location || 'Lisboa',
  localizacao: body.localizacao || body.morada || body.address || null,
  price_ask: body.price_ask || body.price || null,
  tipo_ativo: body.tipo_ativo || body.propertyType || 'apartamento',
  source: body.source || 'apify',
  status: 'new',
  urgency: body.urgency || 'unknown',
  score_status: 'pending_score',
  contacto: body.contacto || body.contact || null,
  notes: body.notes || body.notas || body.description ? (body.notes || body.notas || body.description || '').substring(0, 500) : null
};
return [{ json: lead }];

const resp = $input.first().json;
const lead = Array.isArray(resp) ? resp[0] : resp;
if (!lead || lead.code || lead.error) {
  console.log('Supabase insert error:', JSON.stringify(resp));
  return [{ json: { id: null, _error: true, _raw: JSON.stringify(resp).substring(0,200) } }];
}
let score = 30;
const hotCities = ['Lisboa','Cascais','Comporta','Porto','Algarve','Funchal','Sintra'];
if (hotCities.some(c => (lead.cidade||'').includes(c))) score += 20;
if (lead.price_ask) {
  if (lead.price_ask >= 3000000) score += 25;
  else if (lead.price_ask >= 1000000) score += 20;
  else if (lead.price_ask >= 500000) score += 10;
}
if (lead.urgency === 'high') score += 15;
else if (lead.urgency === 'medium') score += 8;
if (lead.contacto) score += 5;
score = Math.min(score, 100);
const tier = score >= 70 ? 'A' : score >= 40 ? 'B' : 'C';
return [{ json: { ...lead, computed_score: score, tier } }];

const mbResp = $input.first().json;
const lead = $("Code — Score + Tier").item.json;
const mbData = {};
if (mbResp && !mbResp.error && !mbResp.code) {
  if (mbResp.deal_priority_score !== undefined) mbData.deal_priority_score = mbResp.deal_priority_score;
  if (mbResp.matched_buyers_count !== undefined) mbData.matched_buyers_count = mbResp.matched_buyers_count;
  if (mbResp.attack_recommendation) mbData.attack_recommendation = mbResp.attack_recommendation;
  if (mbResp.preclose_candidate !== undefined) mbData.preclose_candidate = mbResp.preclose_candidate;
}
return [{ json: { ...lead, ...mbData } }];
